import * as React from "react";
import PropTypes from "prop-types";

import { Layout, PostCard, Pagination } from "../components";
import { MetaData } from "../components/meta";

// 讀取本地 JSON 檔案作為標籤與文章數據來源
import data from "../data/blog.json";

/**
 * Tag page (/tag/:slug)
 *
 * Loads all posts for a given tag from a local JSON file instead of Ghost CMS.
 */
const Portfolio = ({ location, pageContext }) => {
    const tag = data.ghostPortfolio;
    const posts = data.allGhostPost.edges;

    return (
        <>
            <MetaData location={location} title={tag.meta_title} description={tag.meta_description} type="series" />
            <Layout>
                <div className="container">
                    <header className="tag-header">
                        <h1>{tag.name}</h1>
                        {tag.description && <p>{tag.description}</p>}
                    </header>

                    <section className="post-feed">
                        {posts.length > 0 ? (
                            posts
                                .filter(({ node }) => node.portfolio_visible === true)
                                .map(({ node }) => <PostCard key={node.id} post={node} />)
                        ) : (
                            <p>No posts available under this tag.</p>
                        )}
                    </section>

                    <Pagination pageContext={pageContext} />
                </div>
            </Layout>
        </>
    );
};

Portfolio.propTypes = {
    location: PropTypes.shape({
        pathname: PropTypes.string.isRequired,
    }).isRequired,
    pageContext: PropTypes.object,
};

export default Portfolio;
